using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10m, 2), ("Gadget", 25m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45m, order.Total);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_SetsCorrectTotal()
    {
        var items = CreateItems(("Widget", 15.50m, 3));

        var order = _service.CreateOrder("cust-2", items);

        Assert.AreEqual(46.50m, order.Total);
        Assert.HasCount(1, order.Items);
    }

    [TestMethod]
    public void CreateOrder_GeneratesUniqueIds()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order1 = _service.CreateOrder("cust-1", items);
        var order2 = _service.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_SetsCreatedAtToUtcNow()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, items));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
    }

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAll()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        var results = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var results = _service.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OnlyReturnsMatchingCustomer()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);
        _service.CreateOrder("cust-2", items);

        var results = _service.GetOrdersByCustomer("cust-2");

        var single = Assert.ContainsSingle(results);
        Assert.AreEqual("cust-2", single.CustomerId);
    }

    #endregion

    #region DataRow - total calculation

    [TestMethod]
    [DataRow(10, 1, 10, DisplayName = "Single unit")]
    [DataRow(10, 5, 50, DisplayName = "Multiple units")]
    [DataRow(0, 3, 0, DisplayName = "Zero price")]
    public void CreateOrder_CalculatesTotal_Correctly(int price, int qty, int expectedTotal)
    {
        var items = CreateItems(("Item", price, qty));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    #endregion
}

